import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Input,
  Select,
  SearchInput,
  MoneyInput,
  addToast,
  utcToLocalInputValue,
  localInputToISOWithOffset,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { CreateFixedAssetDto, UpdateFixedAssetDto } from '../../../services/tscd/models';
import { createAccountSearchConfig } from '../../../components/search';
import { DocumentFormHeader } from '../../../components/layout';
import { UnsavedChangesModal } from '../../../components/form/UnsavedChangesModal';
import { useUnsavedChangesGuard } from '../../../hooks/useUnsavedChangesGuard';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { scrollToValidationTarget } from '../../../utils/scrollToValidationTarget';
import { TSCD_DEPRECIATION_METHOD_OPTIONS } from '../../../constants/tscdDepreciationMethods';
import df from '../../../styles/documentForm.module.css';

const TSCD_FIELD_ORDER = [
  'name',
  'categoryCode',
  'originalCost',
  'usefulLifeMonths',
  'depreciationMethod',
  'acquiredDate',
  'accountCode',
  'depreciationExpenseAccountCode',
  'accumDepreciationAccountCode',
] as const;

type TscdFieldKey = (typeof TSCD_FIELD_ORDER)[number];

type TscdFieldErrors = Partial<Record<TscdFieldKey, string>>;

function scrollToFirstTscdFieldError(errors: TscdFieldErrors): void {
  const first = TSCD_FIELD_ORDER.find(k => errors[k]);
  if (first) scrollToValidationTarget(`tscd-field-${first}`);
}

const TscdFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isNew = !id;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const [name, setName] = useState('');
  const [categoryCode, setCategoryCode] = useState('');
  const [originalCost, setOriginalCost] = useState(0);
  const [usefulLifeMonths, setUsefulLifeMonths] = useState(60);
  const [depreciationMethod, setDepreciationMethod] = useState('StraightLine');
  const [accountCode, setAccountCode] = useState('211');
  const [accountName, setAccountName] = useState('');
  const [depreciationExpenseAccountCode, setDepreciationExpenseAccountCode] = useState('627');
  const [depreciationExpenseAccountName, setDepreciationExpenseAccountName] = useState('');
  const [accumDepreciationAccountCode, setAccumDepreciationAccountCode] = useState('214');
  const [accumDepreciationAccountName, setAccumDepreciationAccountName] = useState('');
  const [acquiredDate, setAcquiredDate] = useState(new Date().toISOString().slice(0, 10));
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<TscdFieldErrors>({});
  const [isDirty, setIsDirty] = useState(false);
  const loadedRef = useRef(false);

  const patchFieldError = useCallback((key: TscdFieldKey, value?: string) => {
    setFieldErrors(prev => {
      if (!value) {
        if (!(key in prev)) return prev;
        const next = { ...prev };
        delete next[key];
        return next;
      }
      return { ...prev, [key]: value };
    });
  }, []);

  const markDirty = useCallback(() => {
    if (loadedRef.current) setIsDirty(true);
  }, []);

  const {
    showUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, true);

  useEffect(() => {
    if (isNew) {
      loadedRef.current = true;
      return;
    }
    let cancelled = false;
    setLoading(true);
    loadedRef.current = false;
    const t = setTimeout(() => {
      tscdService.getAsset(id!)
        .then(a => {
          if (cancelled) return;
          setName(a.name);
          setCategoryCode(a.categoryCode);
          setOriginalCost(a.originalCost);
          setUsefulLifeMonths(a.usefulLifeMonths);
          setDepreciationMethod(a.depreciationMethod);
          setAcquiredDate(utcToLocalInputValue(a.acquiredDate));
          setAccountCode(a.accountCode ?? '211');
          setDepreciationExpenseAccountCode(a.depreciationAccountCode ?? '627');
          setAccumDepreciationAccountCode(a.accumDepreciationAccountCode ?? '214');
          setAccountName('');
          setDepreciationExpenseAccountName('');
          setAccumDepreciationAccountName('');
          setIsDirty(false);
          loadedRef.current = true;
        })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải TSCĐ'), type: 'error' }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, dispatch]);

  const validate = (): TscdFieldErrors => {
    const errors: TscdFieldErrors = {};
    if (!name.trim()) errors.name = 'Tên TSCĐ là bắt buộc';
    if (!categoryCode.trim()) errors.categoryCode = 'Mã loại là bắt buộc';
    if (originalCost <= 0) errors.originalCost = 'Nguyên giá phải lớn hơn 0';
    if (usefulLifeMonths <= 0) errors.usefulLifeMonths = 'Thời gian KH phải lớn hơn 0';
    if (!depreciationMethod) errors.depreciationMethod = 'Phương pháp KH là bắt buộc';
    if (isNew && !acquiredDate) errors.acquiredDate = 'Ngày mua là bắt buộc';
    if (!accountCode.trim()) errors.accountCode = 'TK TSCĐ là bắt buộc';
    if (!depreciationExpenseAccountCode.trim()) errors.depreciationExpenseAccountCode = 'TK chi phí KH là bắt buộc';
    if (!accumDepreciationAccountCode.trim()) errors.accumDepreciationAccountCode = 'TK hao mòn lũy kế là bắt buộc';
    return errors;
  };

  const buildBaseDto = (): UpdateFixedAssetDto => ({
    name: name.trim(),
    categoryCode: categoryCode.trim(),
    originalCost: Number(originalCost),
    usefulLifeMonths: Number(usefulLifeMonths),
    depreciationMethod,
    accountCode: accountCode.trim(),
    depreciationExpense: { accountCode: depreciationExpenseAccountCode.trim() },
    accumDepreciation: { accountCode: accumDepreciationAccountCode.trim() },
  });

  const buildCreateDto = (): CreateFixedAssetDto => ({
    ...buildBaseDto(),
    acquiredDate: localInputToISOWithOffset(acquiredDate),
  });

  const handleSave = async () => {
    const errors = validate();
    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      scrollToFirstTscdFieldError(errors);
      dispatch(addToast({ message: 'Vui lòng kiểm tra các trường bắt buộc', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      if (isNew) {
        const created = await tscdService.createAsset(buildCreateDto());
        setIsDirty(false);
        dispatch(addToast({ message: 'Tạo TSCĐ thành công', type: 'success' }));
        navigate(`/tscd/${created.id}`);
      } else {
        await tscdService.updateAsset(id!, buildBaseDto());
        setIsDirty(false);
        dispatch(addToast({ message: 'Cập nhật thành công', type: 'success' }));
      }
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi lưu'), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleBack = () => guardedAction(() => navigate('/tscd/danh-sach'));

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div className={df.page} data-testid="tscd-form">
      <DocumentFormHeader
        onBack={handleBack}
        title={isNew ? 'Thêm tài sản cố định' : `TSCĐ — ${name}`}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo TSCĐ"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />

      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin tài sản</h2>
        <div className={df.row4}>
          <div className={df.field} id="tscd-field-name">
            <label className={df.label}>Tên TSCĐ *</label>
            <Input
              value={name}
              onChange={e => { setName(e.target.value); markDirty(); patchFieldError('name'); }}
              error={fieldErrors.name}
              required
              data-testid="tscd-field-name"
            />
          </div>
          <div className={df.field} id="tscd-field-categoryCode">
            <label className={df.label}>Mã loại *</label>
            <Input
              value={categoryCode}
              onChange={e => { setCategoryCode(e.target.value); markDirty(); patchFieldError('categoryCode'); }}
              error={fieldErrors.categoryCode}
              required
              data-testid="tscd-field-categoryCode"
            />
          </div>
          <div className={df.field} id="tscd-field-originalCost">
            <label className={df.label}>Nguyên giá *</label>
            <MoneyInput
              value={originalCost}
              onChange={val => { setOriginalCost(val); markDirty(); patchFieldError('originalCost'); }}
              error={fieldErrors.originalCost}
              data-testid="tscd-field-originalCost"
            />
          </div>
          <div className={df.field} id="tscd-field-usefulLifeMonths">
            <label className={df.label}>Thời gian KH (tháng) *</label>
            <Input
              type="number"
              min={1}
              value={String(usefulLifeMonths)}
              onChange={e => { setUsefulLifeMonths(Number(e.target.value)); markDirty(); patchFieldError('usefulLifeMonths'); }}
              error={fieldErrors.usefulLifeMonths}
              required
              data-testid="tscd-field-usefulLifeMonths"
            />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field} id="tscd-field-depreciationMethod">
            <label className={df.label}>Phương pháp KH *</label>
            <Select
              value={depreciationMethod}
              onChange={e => { setDepreciationMethod(e.target.value); markDirty(); patchFieldError('depreciationMethod'); }}
              options={TSCD_DEPRECIATION_METHOD_OPTIONS}
              error={fieldErrors.depreciationMethod}
              required
              data-testid="tscd-field-depreciationMethod"
            />
          </div>
          <div className={df.field} id="tscd-field-acquiredDate">
            <label className={df.label}>Ngày mua *</label>
            <Input
              type="date"
              value={acquiredDate}
              onChange={e => { setAcquiredDate(e.target.value); markDirty(); patchFieldError('acquiredDate'); }}
              error={fieldErrors.acquiredDate}
              required={isNew}
              disabled={!isNew}
              data-testid="tscd-field-acquiredDate"
            />
          </div>
          <div className={df.field} id="tscd-field-accountCode" data-testid="tscd-field-accountCode">
            <label className={df.label}>TK TSCĐ *</label>
            <SearchInput
              config={accountSearchConfig}
              value={accountCode}
              primaryDisplay={accountCode}
              secondaryDisplay={accountName}
              clearOnType
              onChange={a => {
                setAccountCode(a.code);
                setAccountName(a.name);
                markDirty();
                patchFieldError('accountCode');
              }}
              onClear={() => {
                setAccountCode('');
                setAccountName('');
                markDirty();
                patchFieldError('accountCode');
              }}
              error={fieldErrors.accountCode}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
          <div className={df.field} id="tscd-field-depreciationExpenseAccountCode" data-testid="tscd-field-depreciationExpenseAccountCode">
            <label className={df.label}>TK chi phí KH *</label>
            <SearchInput
              config={accountSearchConfig}
              value={depreciationExpenseAccountCode}
              primaryDisplay={depreciationExpenseAccountCode}
              secondaryDisplay={depreciationExpenseAccountName}
              clearOnType
              onChange={a => {
                setDepreciationExpenseAccountCode(a.code);
                setDepreciationExpenseAccountName(a.name);
                markDirty();
                patchFieldError('depreciationExpenseAccountCode');
              }}
              onClear={() => {
                setDepreciationExpenseAccountCode('');
                setDepreciationExpenseAccountName('');
                markDirty();
                patchFieldError('depreciationExpenseAccountCode');
              }}
              error={fieldErrors.depreciationExpenseAccountCode}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field} id="tscd-field-accumDepreciationAccountCode" data-testid="tscd-field-accumDepreciationAccountCode">
            <label className={df.label}>TK hao mòn lũy kế *</label>
            <SearchInput
              config={accountSearchConfig}
              value={accumDepreciationAccountCode}
              primaryDisplay={accumDepreciationAccountCode}
              secondaryDisplay={accumDepreciationAccountName}
              clearOnType
              onChange={a => {
                setAccumDepreciationAccountCode(a.code);
                setAccumDepreciationAccountName(a.name);
                markDirty();
                patchFieldError('accumDepreciationAccountCode');
              }}
              onClear={() => {
                setAccumDepreciationAccountCode('');
                setAccumDepreciationAccountName('');
                markDirty();
                patchFieldError('accumDepreciationAccountCode');
              }}
              error={fieldErrors.accumDepreciationAccountCode}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
        </div>
      </div>

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
      />
    </div>
  );
};

export default TscdFormPage;
